     1→import {
     2→  access,
     3→  copyFile,
     4→  cp,
     5→  lstat,
     6→  mkdir,
     7→  readFile,
     8→  realpath,
     9→  rename,
    10→  rm,
    11→  symlink,
    12→  unlink,
    13→  writeFile,
    14→} from "node:fs/promises";
    15→import path from "node:path";
    16→import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
    17→import { UserError } from "../errors.ts";
    18→import { logger } from "../logger.ts";
    19→import type {
    20→  AgentId,
    21→  ConfigPatchDeployAction,
    22→  DeployAction,
    23→  FileWriteDeployAction,
    24→  Manifest,
    25→  PlannedChange,
    26→  SkillDirDeployAction,
    27→} from "../types.ts";
    28→import {
    29→  lookupDeployment,
    30→  registerDeployment,
    31→  verifyDeployment,
    32→} from "./ownership.ts";
    33→import { getDeployMethod, resolveAgentSkillPath } from "./resolve.ts";
    34→
    35→function isPlainObject(v: unknown): v is Record<string, unknown> {
    36→  return typeof v === "object" && v !== null && !Array.isArray(v);
    37→}
    38→
    39→async function readJsonConfig(
    40→  filePath: string,
    41→): Promise<Record<string, unknown>> {
    42→  let rawContent: string;
    43→  try {
    44→    rawContent = await readFile(filePath, "utf-8");
    45→  } catch (err) {
    46→    const code = (err as NodeJS.ErrnoException).code;
    47→    if (code === "ENOENT")
    48→      throw new Error(`Config file not found: ${filePath}`);
    49→    throw err;
    50→  }
    51→  let parsed: unknown;
    52→  try {
    53→    parsed = JSON.parse(rawContent);
    54→  } catch {
    55→    throw new Error(`Config file is not valid JSON: ${filePath}`);
    56→  }
    57→  if (!isPlainObject(parsed)) {
    58→    throw new Error(`Config file is not a JSON object: ${filePath}`);
    59→  }
    60→  return parsed;
    61→}
    62→
    63→function computeUndoPatch(
    64→  original: Record<string, unknown>,
    65→  patch: Record<string, unknown>,
    66→): Record<string, unknown> {
    67→  const undoPatch: Record<string, unknown> = {};
    68→  for (const key of Object.keys(patch)) {
    69→    undoPatch[key] = key in original ? original[key] : null;
    70→  }
    71→  return undoPatch;
    72→}
    73→
    74→function applyMergePatch(
    75→  original: Record<string, unknown>,
    76→  patch: Record<string, unknown>,
    77→): Record<string, unknown> {
    78→  const patched: Record<string, unknown> = { ...original };
    79→  for (const [key, value] of Object.entries(patch)) {
    80→    if (value === null) {
    81→      delete patched[key];
    82→    } else {
    83→      patched[key] = value;
    84→    }
    85→  }
    86→  return patched;
    87→}
    88→
    89→function sourceAccessError(err: unknown, sourcePath: string): string {
    90→  const code = (err as NodeJS.ErrnoException).code;
    91→  if (code === "ENOENT") return `Source not found: ${sourcePath}`;
    92→  if (code === "EACCES" || code === "EPERM")
    93→    return `Permission denied accessing source: ${sourcePath}`;
    94→  const detail = err instanceof Error ? err.message : String(err);
    95→  return `Failed to access source ${sourcePath}: ${detail}`;
    96→}
    97→
    98→export async function planDeploy(
    99→  manifest: Manifest,
   100→  sourceDir: string,
   101→  detectedAgents: AgentId[],
   102→  home: string,
   103→): Promise<DeployAction[]> {
   104→  const method = getDeployMethod();
   105→  const actions: DeployAction[] = [];
   106→  const resolvedSourceDir = path.resolve(sourceDir);
   107→
   108→  let realRoot: string;
   109→  try {
   110→    realRoot = await realpath(resolvedSourceDir);
   111→  } catch {
   112→    realRoot = resolvedSourceDir;
   113→  }
   114→
   115→  for (const skill of manifest.skills) {
   116→    const source = path.resolve(sourceDir, skill.path);
   117→    await validateSourcePath(source, skill.path, resolvedSourceDir, realRoot);
   118→
   119→    await validateSkillContract(source, skill.path);
   120→
   121→    for (const agentId of skill.agents) {
   122→      if (!detectedAgents.includes(agentId)) continue;
   123→
   124→      const agent = AGENT_REGISTRY_BY_ID[agentId];
   125→      if (!agent) continue;
   126→
   127→      const target = resolveAgentSkillPath(agent, skill.name, home);
   128→
   129→      actions.push({
   130→        kind: "skill-dir",
   131→        skill: skill.name,
   132→        agent: agentId,
   133→        source,
   134→        target,
   135→        method,
   136→      });
   137→    }
   138→  }
   139→
   140→  return actions;
   141→}
   142→
   143→export async function executeDeploy(
   144→  actions: DeployAction[],
   145→  dryRun: boolean,
   146→  verbose: boolean,
   147→  home: string,
   148→): Promise<{
   149→  succeeded: number;
   150→  failed: Array<{ action: DeployAction; error: string }>;
   151→  planned: PlannedChange[];
   152→}> {
   153→  let succeeded = 0;
   154→  const failed: Array<{ action: DeployAction; error: string }> = [];
   155→  const planned: PlannedChange[] = [];
   156→
   157→  for (const action of actions) {
   158→    switch (action.kind) {
   159→      case "skill-dir": {
   160→        const result = await deploySkillDir(
   161→          action,
   162→          dryRun,
   163→          verbose,
   164→          home,
   165→          planned,
   166→        );
   167→        if (result.error === null) {
   168→          succeeded++;
   169→        } else {
   170→          failed.push({ action, error: result.error });
   171→        }
   172→        break;
   173→      }
   174→      case "file-write": {
   175→        const result = await deployFileWrite(
   176→          action,
   177→          dryRun,
   178→          verbose,
   179→          home,
   180→          planned,
   181→        );
   182→        if (result.error === null) {
   183→          succeeded++;
   184→        } else {
   185→          failed.push({ action, error: result.error });
   186→        }
   187→        break;
   188→      }
   189→      case "config-patch": {
   190→        const result = await deployConfigPatch(
   191→          action,
   192→          dryRun,
   193→          verbose,
   194→          home,
   195→          planned,
   196→        );
   197→        if (result.error === null) {
   198→          succeeded++;
   199→        } else {
   200→          failed.push({ action, error: result.error });
   201→        }
   202→        break;
   203→      }
   204→      default: {
   205→        throw new Error(`Unhandled deploy action kind: ${action}`);
   206→      }
   207→    }
   208→  }
   209→
   210→  return { succeeded, failed, planned };
   211→}
   212→
   213→async function deploySkillDir(
   214→  action: SkillDirDeployAction,
   215→  dryRun: boolean,
   216→  verbose: boolean,
   217→  home: string,
   218→  planned: PlannedChange[],
   219→): Promise<{ error: string | null }> {
   220→  const label = `${action.skill} -> ${action.agent}`;
   221→
   222→  try {
   223→    await access(action.source);
   224→  } catch (err) {
   225→    const msg = sourceAccessError(err, action.source);
   226→    logger.fail(label, msg);
   227→    return { error: msg };
   228→  }
   229→
   230→  if (dryRun) {
   231→    logger.plan(label);
   232→    logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
   233→    planned.push({
   234→      verb: action.method === "symlink" ? "create-symlink" : "copy-dir",
   235→      kind: "skill-dir",
   236→      skill: action.skill,
   237→      agent: action.agent,
   238→      source: action.source,
   239→      target: action.target,
   240→      method: action.method,
   241→    });
   242→    return { error: null };
   243→  }
   244→
   245→  try {
   246→    await executeDeployAction(action, verbose, home);
   247→    return { error: null };
   248→  } catch (err) {
   249→    const msg = err instanceof Error ? err.message : String(err);
   250→    logger.fail(label, msg);
   251→    return { error: msg };
   252→  }
   253→}
   254→
   255→async function deployFileWrite(
   256→  action: FileWriteDeployAction,
   257→  dryRun: boolean,
   258→  verbose: boolean,
   259→  home: string,
   260→  planned: PlannedChange[],
   261→): Promise<{ error: string | null }> {
   262→  const label = `${action.skill} -> ${action.agent}`;
   263→
   264→  try {
   265→    await access(action.source);
   266→  } catch (err) {
   267→    const msg = sourceAccessError(err, action.source);
   268→    logger.fail(label, msg);
   269→    return { error: msg };
   270→  }
   271→
   272→  if (dryRun) {
   273→    logger.plan(label);
   274→    logger.detail(`write-file: ${action.source} -> ${action.target}`);
   275→    planned.push({
   276→      verb: "write-file",
   277→      kind: "file-write",
   278→      skill: action.skill,
   279→      agent: action.agent,
   280→      source: action.source,
   281→      target: action.target,
   282→    });
   283→    return { error: null };
   284→  }
   285→
   286→  try {
   287→    // Check if target exists — only allow overwrite if we own it
   288→    try {
   289→      await lstat(action.target);
   290→      const isOwned = await verifyDeployment(home, action.target, {
   291→        kind: "file-write",
   292→        source: action.source,
   293→        skill: action.skill,
   294→        agent: action.agent,
   295→      });
   296→      if (!isOwned) {
   297→        throw new Error(
   298→          `Target "${action.target}" exists but is not managed by inception-engine — refusing to overwrite`,
   299→        );
   300→      }
   301→    } catch (err) {
   302→      if (err instanceof Error && err.message.includes("refusing to overwrite"))
   303→        throw err;
   304→      // ENOENT — target doesn't exist, fine to create
   305→    }
   306→
   307→    await mkdir(path.dirname(action.target), { recursive: true });
   308→    await copyFile(action.source, action.target);
   309→    await registerDeployment(home, action.target, {
   310→      kind: "file-write",
   311→      source: action.source,
   312→      skill: action.skill,
   313→      agent: action.agent,
   314→    });
   315→    logger.ok(label);
   316→    if (verbose) {
   317→      logger.detail(`write-file: ${action.source} -> ${action.target}`);
   318→    }
   319→    return { error: null };
   320→  } catch (err) {
   321→    const msg = err instanceof Error ? err.message : String(err);
   322→    logger.fail(label, msg);
   323→    return { error: msg };
   324→  }
   325→}
   326→
   327→async function deployConfigPatch(
   328→  action: ConfigPatchDeployAction,
   329→  dryRun: boolean,
   330→  verbose: boolean,
   331→  home: string,
   332→  planned: PlannedChange[],
   333→): Promise<{ error: string | null }> {
   334→  const label = `${action.skill} -> ${action.agent}`;
   335→
   336→  if (!isPlainObject(action.patch)) {
   337→    const msg = `Config patch for skill "${action.skill}" must be a plain object`;
   338→    logger.fail(label, msg);
   339→    return { error: msg };
   340→  }
   341→
   342→  const patch = action.patch;
   343→
   344→  if (dryRun) {
   345→    logger.plan(label);
   346→    logger.detail(`patch-config: ${JSON.stringify(patch)} -> ${action.target}`);
   347→    planned.push({
   348→      verb: "patch-config",
   349→      kind: "config-patch",
   350→      skill: action.skill,
   351→      agent: action.agent,
   352→      target: action.target,
   353→      patch,
   354→    });
   355→    return { error: null };
   356→  }
   357→
   358→  try {
   359→    // Guard against double-patching by a different skill/agent
   360→    const existingEntry = await lookupDeployment(home, action.target);
   361→    if (
   362→      existingEntry &&
   363→      (existingEntry.skill !== action.skill ||
   364→        existingEntry.agent !== action.agent)
   365→    ) {
   366→      throw new Error(
   367→        `Config "${action.target}" is already patched by skill "${existingEntry.skill}" for agent "${existingEntry.agent}" — refusing to double-patch`,
   368→      );
   369→    }
   370→
   371→    const original = await readJsonConfig(action.target);
