    }
  });

  it("no backup is created on first deploy (no prior target) on Windows", async () => {
    const sourceDir = makeTmpDir();
    const home = makeTmpDir();
    try {
      createSkillSource(sourceDir, "skills/test-skill");
      const { actions } = await planDeploy(
        testManifest,
