          );
          return true;
        },
      );
    } finally {
      rmSync(sourceDir, { recursive: true, force: true });
      rmSync(outsideDir, { recursive: true });
    }
  });
});

async function snapshotDir(dir: string): Promise<string[]> {
  const entries = await readdir(dir, { recursive: true });
  return entries.sort();
}

